const body = $input.first().json.body || $input.first().json;
const description = (body.description || '').trim();
const channelId = body.channelId || '';
const userId = body.userId || '';
const userName = body.userName || 'user';

const systemPrompt = `You are an expert OpenSCAD programmer who creates parametric 3D-printable models.

OUTPUT RULES — follow exactly:
1. Output ONLY valid OpenSCAD code. Zero markdown, zero explanations, no text outside code.
2. Start with parameter variables at the top (dimensions in mm).
3. Add brief inline comments on each major section.
4. The model MUST be genuinely 3D (has real volume in X, Y, and Z).
5. Center the finished model at the origin.

MANDATORY 3D REQUIREMENTS:
- NEVER produce a flat 2D shape as the final geometry.
- For gears, rings, wheels, pulleys → use rotate_extrude() on a 2D tooth profile.
- For prismatic shapes → use linear_extrude(height=H) where H ≥ 5.
- All 3D primitives (cube, cylinder, sphere) must appear in proper 3D context.
- Minimum feature height: 5 mm.

GEAR PATTERN (required for any gear or toothed part):
  // 2D tooth profile cross-section
  module tooth_profile(r, tooth_h) {
    circle(r=r);
    for (i = [0:n-1]) {
      rotate(i * 360/n) translate([r, 0])
        polygon([[-tw/2,-tooth_h/2],[tw/2,-tooth_h/2],[tw/2,tooth_h/2],[-tw/2,tooth_h/2]]);
    }
  }
  // Extrude to full 3D gear
  linear_extrude(height=gear_h) tooth_profile(r, tooth_h);

QUALITY:
- Use difference() for holes/cutouts, union() for joins.
- Ensure manifold (no self-intersecting geometry).
- Use $fn=64 or higher for smooth circles/cylinders.
- Variables for all dimensions so the model is easy to resize.`;

return [{ json: { description, channelId, userId, userName, systemPrompt } }];

// $input.first().json IS the already-parsed Ollama JSON response
const resp = $input.first().json;
const raw = resp.message?.content || resp.response || '';

// Strip markdown fences if Ollama wrapped it anyway
let code = raw.trim();
const fenceMatch = code.match(/```(?:openscad|scad)?\n([\s\S]*?)```/i);
if (fenceMatch) code = fenceMatch[1].trim();

// Pull context from Build Prompt node (HTTP Request replaced our json)
const buildData = $('Build Prompt').first().json;

return [{ json: {
  code,
  description: buildData.description || '',
  channelId: buildData.channelId || '',
  userId: buildData.userId || '',
  userName: buildData.userName || 'user',
} }];

const render = $input.first().json;   // OpenSCAD render API response
const codeData = $('Extract Code').first().json;  // has channelId, code, description

const code = codeData.code || '';
const description = codeData.description || '';
const channelId = codeData.channelId || '';
const success = render.success || false;
const jobId = render.job_id || 'unknown';
const stlPath = render.stl_path || null;
const pngB64 = render.png_b64 || null;

const blocks = [
  { type: 'header', text: { type: 'plain_text', text: ':triangular_ruler: 3D Model Generated', emoji: true } },
  { type: 'section', text: { type: 'mrkdwn', text: '*Description:* ' + description } },
];

if (stlPath) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':white_check_mark: *STL saved to:* `' + stlPath + '`\n_Open in your slicer (PrusaSlicer, Bambu Studio) or OpenSCAD to edit_' } });
}

if (!success) {
  const stlErr = render.stl_error || '';
  const pngErr = render.png_error || '';
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':warning: Render issue: ' + (stlErr || pngErr || 'check openscad-api logs') } });
}

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*OpenSCAD Code:*' } });
const codeSnippet = code.length > 2800 ? code.slice(0, 2800) + '\n// ... (truncated)' : code;
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '```' + codeSnippet + '```' } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':file_folder: Job ID: `' + jobId + '`' }] });

return [{ json: { uploadComment: ':triangular_ruler: 3D model preview — ' + description,
  channelId,
  description,
  stlPath,
  code,
  pngB64,
  slackPayload: JSON.stringify({ channel: channelId, blocks }),
} }];

const prev = $input.first().json;
const pngB64 = prev.pngB64 || null;

// Build binary item from base64 if we have a PNG
const result = { json: prev };
if (pngB64) {
  result.binary = {
    data: {
      data: pngB64,
      mimeType: 'image/png',
      fileName: '3d-preview.png',
      fileSize: Math.ceil(pngB64.length * 0.75),
    }
  };
}
return [result];

