={{ (() => {
  const d = $('Upload to Slack').first().json;
  const channelId = d.channelId || '';
  const description = d.description || '';
  const stlPath = d.stlPath || null;
  const code = d.code || '';
  const success = d.success !== false;

  const codeSnippet = code.length > 2700
    ? code.slice(0, 2700) + '\n// ... (full file at ' + (stlPath || '').replace(/\.stl$/, '.scad') + ')'
    : code;

  const blocks = [
    { type: 'header', text: { type: 'plain_text', text: ':triangular_ruler: OpenSCAD Source', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*' + description + '*' } },
  ];

  if (!success) {
    blocks.push({ type: 'section', text: { type: 'mrkdwn',
      text: ':warning: *Render issues detected* — model may need adjustment in OpenSCAD' } });
  }

  blocks.push({ type: 'section', text: { type: 'mrkdwn',
    text: '```\n' + codeSnippet + '\n```' } });

  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn',
    text: ':printer: Paste code into OpenSCAD to preview · Slice the STL in your slicer to print' }] });

  return JSON.stringify({ channel: channelId, blocks });
})() }}

